      "assets/GameScript/labels/story_01.sks": ScriptNode(<SksNode>[
        LabelNode("story_01"),
        BackgroundNode("schoolg-day", timer: null, layers: null, transitionType: "wipe", animation: null, repeatCount: null),
        SayNode(character: null, dialogue: "从教室走了出来。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 14, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我已经不能再次失败。", dialogueTag: "angry", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 15, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        PlaySoundNode("sfx_001", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "修士", "bg": "#210A4F", "color": "#AB20A1", "fit": "width", "plain": "true", "anim": "none", "duration": "1", "wait": "true", "gapBg": "#17051F"}),
        PlaySoundNode("sfx_001", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "简单来说，就是日本的研究生。\n修士普遍为两年制，\n即第一年入学，第二年就需要提交毕业论文（修士论文）。", "bg": "#210A4F", "color": "#AB20A1", "plain": "true", "anim": "none", "lineWidths": "1,0.5,0.5", "lineStretch": "true", "duration": "1", "wait": "true", "gapBg": "#17051F"}),
        PlaySoundNode("sfx_001", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "※另外，日本的“研究生”实际上是修士预备生的意思。\n※另外，日本的“研究生”实际上是修士预备生的意思。\n修士分为10月入学的10月生，和4月入学的4月生。\n修士分为10月入学的10月生，和4月入学的4月生。\n入学两年后同时间毕业。\n入学两年后同时间毕业。", "bg": "#FEFEFE", "color": "#AB20A1", "plain": "true", "anim": "none", "lineWidths": "1,1,0.8,0.8,0.5,0.5", "lineStretch": "true", "duration": "1", "wait": "true", "gapBg": "#17051F"}),
        PlaySoundNode("sfx_001", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "时下6月1日。\n本人，前年十月入学，至今已满一年有余。", "bg": "#210A4F", "color": "#AB20A1", "plain": "true", "anim": "none", "lineWidths": "1,1", "duration": "1", "wait": "true", "gapBg": "#17051F"}),
        PlaySoundNode("sfx_001", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "也就是说——", "bg": "#FEFEFE", "color": "#AB20A1", "fit": "cover", "plain": "true", "anim": "none", "lineWidths": "1", "lineStretch": "true", "duration": "1", "wait": "true", "gapBg": "#17051F"}),
        PlaySoundNode("sfx_001", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "时间：6月1日。\n目标：7月末提出修士毕业论文！\n时间表：\n·6月 完成初稿\n·7月 提交初稿并根据教授意见修改\n·8月 定稿，答辩\n·9月 毕业※其实是“修了”", "bg": "#210A4F", "color": "#AB20A1", "fit": "width", "plain": "true", "anim": "none", "align": "left", "duration": "1.5", "wait": "true", "gapBg": "#17051F"}),
        PlaySoundNode("sfx_002", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "剩余时间：61天\n现有进度：0", "bg": "#000000", "color": "#AB20A1", "fit": "screen", "plain": "true", "anim": "statusgrow", "align": "center", "outline": "#FEFEFE", "outlineWidth": "5", "duration": "6", "wait": "true"}),
        PlayMusicNode("bgm_002.mp3"),
        SayNode(character: null, dialogue: "6月，将生未生的夏季。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 44, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "为了不要走向灭亡，我只能做出唯一的选项——", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 45, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "必须要和地雷女说上话！", dialogueTag: "angry", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 47, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "哪怕……一句也可以。", dialogueTag: "anxious", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 48, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        PlaySoundNode("sfx_001", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "要问为什么的话——", "bg": "#210A4F", "color": "#AB20A1", "fit": "width", "plain": "true", "anim": "none", "duration": "1", "wait": "true", "gapBg": "#17051F"}),
        PlaySoundNode("book", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "《论郁娇文化——从“地雷系”开始》", "bg": "#210A4F", "color": "#AB20A1", "plain": "true", "anim": "pageflip", "lineWidths": "1,0.5,0.5", "lineStretch": "true", "duration": "1", "wait": "true", "gapBg": "#17051F"}),
        PlaySoundNode("book", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "是我的论文题目。", "bg": "#210A4F", "color": "#AB20A1", "plain": "true", "anim": "pageflip", "lineWidths": "1,1", "duration": "1", "wait": "true", "gapBg": "#17051F"}),
        ApiCallNode("menhera.fullscreen_text.clear", parameters: <String, String>{}),
        SayNode(character: null, dialogue: "我在教学楼的阶梯上，向下走。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 65, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "眼前忽然闪过未来可能发生的惨剧。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 66, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "好丢人好可怜好悲哀好恶心好痛好烦好痛好难受快滚好讨厌好抗拒好想逃走好痛好吵好兴奋好焦躁好烦闷好浮躁好伤心快滚好想哭好痛好想听那首歌好真实好出糗好讨厌被当成小丑好麻烦好想等到明天好烦好烦好烦好烦好烦好烦好烦好烦好想哭好想吐好失望好激动好难受好痛好不要脸快滚太吵了好想堵住耳朵是谁在和我说话好痛不要再说了快从我的面前滚蛋快走开好可怜好可怜好可怜好烦好想成为女主角好可悲好想钻到地底好想逃走好丢人好想哭好想掉这个世界好难受好像被堵住的鼻子好想滚好想逃避好想逃避好想逃避好想逃避好想逃避好想逃避", "bg": "#210A4F", "color": "#AB20A1", "fit": "screen", "plain": "true", "anim": "none", "direction": "vertical-rl", "typewriter": "true", "typewriterDuration": "true", "typewriterSfx": "sfx_001", "typewriterSfxInterval": "0.08", "duration": "5", "postWait": "1", "wait": "true"}),
        ApiCallNode("menhera.fullscreen_text.clear", parameters: <String, String>{}),
        SayNode(character: null, dialogue: "不想被讨厌，不想丢人，比起成为主角，我更想要消失。", dialogueTag: "angry", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 71, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
