        SayNode(character: null, dialogue: "如果不能找到地雷女的话，我就只有死路一条。", dialogueTag: "sad", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 73, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
