        BackgroundNode("roof-dusk", timer: null, layers: null, transitionType: null, animation: null, repeatCount: null),
        PlayMusicNode("bgm_008.mp3"),
        BackgroundNode("roof-dusk", timer: null, layers: null, transitionType: null, animation: null, repeatCount: null),
        SayNode(character: null, dialogue: "过了很久，也可能只是像过了很久。因为我们谁也没有带表，也可能只是我自己。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 268, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "黄昏还是像刚才一样吞没了我们。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 269, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "在这样的情境下，时间好像不存在。谁都无法判明它，所以不存在。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 270, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
