        SayNode(character: null, dialogue: "等我说出，她想知道的答案？", dialogueTag: "anxious", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 283, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
