        SayNode(character: null, dialogue: "几分冰凉的声音，透过耳朵，明明睁着眼睛，却看到了屏幕中的画面，那是比镜中的自己还要熟悉的画面。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 52, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
