        SayNode(character: null, dialogue: "即使，即使是死宅，要说出这样的话也会很不好意思啊！", dialogueTag: "shy", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 189, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
