        ApiCallNode("menhera.fx.clear", parameters: <String, String>{}),
        SayNode(character: null, dialogue: "但是等了很久，终于等到她再开口，也没有生成雾气。", dialogueTag: "fuzu", tailCharacter: "aru3", tailPose: "pose1", tailExpression: "fuzu", tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 290, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「都怪你不说话，鸦露露的巧克力都化在嘴里了啦。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 292, pose: "pose1", expression: "angry", position: null, animation: "fururu2", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
