        SayNode(character: "aru2", dialogue: "「要来一支吗？」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 298, pose: "pose1", expression: "smile", position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
