        SayNode(character: null, dialogue: "所以如果她没有用香水的话，我想那应该是洗发用品的味道。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 313, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
