        PlaySoundNode("sfx_001", loop: false),
        ApiCallNode("menhera.fullscreen_text", parameters: <String, String>{"text": "死宅是这样的！", "bg": "#000000", "color": "#FEFEFE", "fit": "screen", "plain": "true", "anim": "none", "duration": "1.5", "wait": "true"}),
        SayNode(character: null, dialogue: "死宅是这样的！（毛笔字一样的字体）", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 177, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "她将四本书放在结账台上。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 181, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "嗯？", dialogueTag: "anxious", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 183, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "四本？", dialogueTag: "anxious", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 185, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "要知道我偷偷藏了一手才好不容易才抵达三本。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 187, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我手上的三本书，一本是作为交换的漫画，另一本也是作为交换的书《不会被言秋察觉的交往法》，最后一本则是趁她不备偷偷买下的《哥特文化全囊括》。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 189, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "然后我走到柜台前，数起眼前的书。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 191, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "她的四本则是——", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 193, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "作为交换的漫画一本，", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 194, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "作为交换的书《情绪描述词全集》一本，", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 195, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "以及两本《献给百合爱好者的入门讲座》。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 196, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "诶？《献给百合爱好者的入门讲座》？还是两本？", dialogueTag: "anxious", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 198, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "还没有理清逻辑，但是我立刻反应过来——要先阻止她结账！", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 200, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
