        SayNode(character: "aru3", dialogue: "「真是的，居然害怕鸦露露！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 170, pose: null, expression: "sweat", position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "aru3", dialogue: "「 哼，是不是把鸦露露想成吸血鬼了！哪有这么可爱的吸血鬼！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 172, pose: null, expression: "sweat", position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
