        SayNode(character: "aru3", dialogue: "「哇！别哭别哭！怎么越哭越厉害了！！怎么办怎么办！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 181, pose: null, expression: "tears", position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
