        BackgroundNode("street-night", timer: null, layers: null, transitionType: "wipe", animation: null, repeatCount: null),
        SayNode(character: null, dialogue: "就在大脑变成一片全白的时候，一瞬间空气都改变了。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 251, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
