        SayNode(character: null, dialogue: "想要离鸦露露远一些。——啊，原来那真的是鸦露露本人，她没有丢下我啊。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 263, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
