        SayNode(character: "aru2", dialogue: "「我真的很想看！最近这个很有名……等等，不会你已经看过了吧！不要啊——！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 161, pose: null, expression: "surprised", position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
