        SayNode(character: null, dialogue: "看上去却比之前还要更鲜活了……虽然总觉得“鲜活”这个词有些奇怪。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 77, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
