        SayNode(character: "aru3", dialogue: "「所以，只需要一个魔法就好了！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 260, pose: null, expression: "sweat", position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
