        SayNode(character: null, dialogue: "忽然我意识到，这个场景有些眼熟，那是有关在视频网站上见到的另一个她所讲解的某个故事。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 288, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
