        SayNode(character: null, dialogue: "就像是闭上眼也还能看到的，就像是捂住耳也能听到的，总是在我的身旁，在我的脑中成群地游荡。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 244, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
