        SayNode(character: null, dialogue: "可以告诉我你的专业吗？", dialogueTag: "anxious", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 234, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
