        SayNode(character: null, dialogue: "如果没有她的话，我甚至都不知道我知道这些。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 206, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "那这就是对话。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 208, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "除了对话还有可能是什么呢？", dialogueTag: "anxious", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 209, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「电波，就是物理意味上的电波，出现在了这个世界。就像刚才所说的那样，广播，电视等等……因为电波，人们被以与过往有别的方式联系在了一起，而“毒电波”与“电波系”正是人们对这一突然出现的全新的人与人的连接方式的反应。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 211, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「种排异反应呢。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 213, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「对，没错，感到不习惯，感到不自然，感到像是身体中的异物一样。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 215, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「于是产生了怀疑。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 217, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「怀疑这是不是一种骗局。怀疑这背后存在阴谋。怀疑电波的背后存在某种超越性的东西。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 219, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「当时应该还有很典型的案子。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 221, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「是的。这种怀疑生出了恐惧，“电波在向自己说些什么”，“电波在监视自己”，“电波在命令自己”，“我被电波控制了”。当时曾有一个非常著名的案子，犯人声称自己正是被电波所命令，才犯下命案的。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 223, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「那时也引起了轩然大波呢。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 225, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「不仅仅是成为了一个常被人们谈起的事件。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 227, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「并且引起了更多人的同感。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 229, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「是的。最初，对“电波的诞生”抱有不信任感的人就不在少数，甚至，在这个案件之前，就早有许多人不约而同地感受到了“电波的气息”，只是这种弥漫在空气中的……」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 231, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「弥漫在空气中的恐慌……」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 233, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「思想，还有语言。始终没有变成成型的某种东西。但是这个事件却给了一个奇迹，让这些暧昧不明的东西拥有了身体。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 235, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「一跃进入了报纸新闻，进入了主流的视野。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 237, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「并且形成了某种象征。甚至犯人决定性的自述，还会成为某种范式。就像给原本没有名字的东西起了名字。同时被广泛地认识到，且拥有了典型的特征，或者说症状？很快就成为了适合传播的东西。嗯……原本这种不安就是很容易扩散的东西。」", dialogueTag: "anxious", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 239, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「然后……」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 241, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「这个世界上有一类，像是海绵一样，吸收着弥漫在空气中的不安的东西。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 243, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: 2, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「文艺作品。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 245, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「在这样的时代背景下，文艺作品当然吸收了这种“不安”与“恐慌”。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 247, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: 2, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「也是这个时候出现了“毒电波”的名字。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 249, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「攻击人类的毒电波。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 251, pose: "pose_close", expression: "sweat", position: null, animation: "shake2", repeatCount: 3, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「与苦于毒电波的人类们。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 253, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「当名字被确定下来，更广泛地出现在文艺作品中也变成了必然。先是从漫画开始的……应该。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 255, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「在我的印象里也是这样哦！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 257, pose: "pose_close", expression: "sweat", position: null, animation: "jump", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「虽然我也可能记错就是啦！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 258, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「我相信你！」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 260, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「诶！连鸦露露自己都没有很相信鸦露露诶！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 262, pose: "pose_close", expression: "sweat", position: null, animation: "topin", repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「不，我相信你！」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 264, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「好可怕我要产生恐慌了。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 266, pose: "pose_close", expression: "sweat", position: null, animation: "shake2", repeatCount: 4, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「因为我被电波控制了，电波告诉我你说的是正确的。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 268, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「才怪啦！！！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 270, pose: "pose_close", expression: "sweat", position: null, animation: "jump", repeatCount: 2, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「就算有偏差，也肯定在当时有以“毒电波”为题材的漫画！而且很有名！大幅扩展了“毒电波”的知名度。」", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 272, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3r", dialogue: "「侧面也说明了这也是观众想看的内容。也就是说，是一种一直没被言说的人们的共同感受吧？」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 274, pose: "pose_close", expression: "sweat", position: null, animation: "fururu", repeatCount: 2, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我点了点头。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 276, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
