        SayNode(character: null, dialogue: "突然被问到，一下子丢失了刚才的记忆，想要回答她的问题，只好追溯到思维最初的地方。", dialogueTag: "fuzu", tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 18, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
